#include <iostream>
#include <string>
using namespace std;

class Food{
    private:
        string name;
        int price;
        int quantity;
    public:
        // 在此進行輸入的動作
        void setFood(){
            cin >> name >> price >> quantity;
        }

        // 印出物件中的資料
        void printData(){
            cout << name << " " << price << " " << quantity << endl;
        }

        // 計算該物件的總金額
        double getTotal(){
            return price * quantity;
        }
};

// 印出當天三餐資料，並以 "--------" 換行再輸出當日金額
void printDay(Food myFood_1, Food myFood_2, Food myFood_3){
    myFood_1.printData();
    myFood_2.printData();
    myFood_3.printData();

    double dayTotal = myFood_1.getTotal() + myFood_2.getTotal() + myFood_3.getTotal();

    cout << "--------" << endl;
    cout << "當日總花費: " << dayTotal << endl;
}

// 統整一週輸出，並印出一週全部物件的總金額
void printWeek(Food myFood[], int size){
    double weekTotal = 0;

    // 一週有 7 天 (21 / 3 = 7)
    for(int i = 0; i < size / 3; i++){
        int idx = i * 3;

        // 呼叫 printDay 處理一天的資料
        printDay(myFood[idx], myFood[idx+1], myFood[idx+2]);

        // 計算並累加這三餐的總金額到週總計
        weekTotal += myFood[idx].getTotal() + myFood[idx+1].getTotal() + myFood[idx+2].getTotal();

        // 每天之間空一行，最後一天不空
        if(i < (size / 3) - 1){
            cout << endl;
        }
    }

    // 結尾印出一週總花費
    cout << endl << "一周的總花費: " << weekTotal << endl;
}

int main(){
    Food myFood[21];

    // 輸入 21 筆資料
    for(int i=0;i<21;i++)
        myFood[i].setFood();

    // 呼叫 printWeek 進行處理與輸出
    printWeek(myFood, 21);

    return 0;
}

