#include <iostream> 
using namespace std;

void InsertionSort(int list[], int listSize)
{
	for (int i = 1; i < listSize; i++)
	{
		int currentElement = list[i];
		int k;
		for (k = i - 1; k >= 0 && list[k] > currentElement; k--)
		{
			list[k + 1] = list[k];
		}
		list[k + 1] = currentElement;
	}
}

int BinarySearch(const int list[], int key, int listSize)
{
	int low = 0;
	int high = listSize - 1;

	while (high >= low)
	{
		int mid = (low + high) / 2;
		if (key < list[mid])
			high = mid - 1;
		else if (key > list[mid])
			low = mid + 1;
		else
			return mid;
	}

	return -1;
}

