#ifndef STACK_H
#define STACK_H

class Stack
{
public:
    Stack();
    Stack(const Stack &);
    ~Stack();
    bool empty() const;
    int peek() const;
    void push(int value);
    int pop();
    int getSize() const;

private:
    int *elements;
    int size;
    int capacity;
    void ensureCapacity();
};

Stack::Stack() : size(0), capacity(16)
{
    elements = new int[capacity];
}

Stack::Stack(const Stack &stack)
{
    elements = new int[stack.capacity];
    size = stack.size;
    capacity = stack.capacity;
    for (int i = 0; i < size; i++)
    {
        elements[i] = stack.elements[i];
    }
}

Stack::~Stack()
{
    delete[] elements;
}

bool Stack::empty() const
{
    return (size == 0);
}

int Stack::peek() const
{
    return elements[size - 1];
}

void Stack::push(int value)
{
    ensureCapacity();
    elements[size++] = value;
}

void Stack::ensureCapacity()
{
    if (size >= capacity)
    {
        int *old = elements;
        capacity = 2 * size;
        elements = new int[size * 2];

        for (int i = 0; i < size; i++)
            elements[i] = old[i];

        delete[] old;
    }
}

int Stack::pop()
{
    return elements[--size];
}

int Stack::getSize() const
{
    return size;
}

#endif

